import math


def circle_area(radius):
    """Return the area of a circle, rounded to 2 decimal places."""
    return round(math.pi * radius ** 2, 2)


def circle_circumference(radius):
    """Return the circumference of a circle, rounded to 2 decimal places."""
    return round(2 * math.pi * radius, 2)


def sphere_volume(radius):
    """Return the volume of a sphere, rounded to 2 decimal places."""
    return round((4 / 3) * math.pi * radius ** 3, 2)


def degrees_to_radians(degrees):
    """Convert degrees to radians, rounded to 4 decimal places."""
    return round(degrees * (math.pi / 180), 4)
